"""Public overview page for CivicElections."""


def render_public_lookup_page() -> str:
    return """<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>CivicElections - election administration support</title><style>:root{--ink:#18212b;--blue:#1f4d6f;--pale:#e9f2f7;--red:#9d3f3f;--paper:#fff8ea}body{margin:0;font-family:'Aptos','Segoe UI',sans-serif;color:var(--ink);background:linear-gradient(135deg,#eef7fb,var(--paper))}header,main,footer{width:min(1080px,calc(100% - 32px));margin:auto}header{padding:52px 0 20px}.eyebrow{text-transform:uppercase;letter-spacing:.14em;color:var(--blue);font-weight:900}h1{font:800 clamp(2.35rem,7vw,5.2rem)/.95 Georgia,serif;margin:.1em 0}.lede{font-size:1.2rem;line-height:1.6;max-width:850px}.grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:18px}.card{background:rgba(255,255,255,.92);border:1px solid #bdd0dd;border-radius:24px;padding:24px;box-shadow:0 18px 36px #26313b18}.badge{display:inline-block;background:var(--blue);color:white;padding:.5rem .85rem;border-radius:999px;font-weight:900}code{background:var(--pale);padding:.1rem .35rem;border-radius:.35rem}:focus-visible{outline:4px solid var(--red);outline-offset:3px}@media(max-width:720px){.grid{grid-template-columns:1fr}header{padding-top:34px}}</style></head><body><header><p class="eyebrow">CivicSuite / CivicElections</p><h1>Election administration support without touching voting systems.</h1><p class="lede">CivicElections v0.1.0 helps clerks prepare cited voter guidance, candidate filing checklists, worker training answers, ballot-summary drafts, campaign-finance summaries, canvass checklists, and accessibility reviews.</p><p><span class="badge">Shipping v0.1.0</span></p></header><main><section class="grid"><article class="card"><h2>What ships</h2><ul><li>Voter guidance outlines.</li><li>Candidate filing checklists.</li><li>Ballot-summary drafts.</li><li>Canvass and accessibility checklists.</li></ul></article><article class="card"><h2>Clerk approval required</h2><p>Election officials approve all guidance, dates, ballot summaries, canvass materials, and public text.</p></article><article class="card"><h2>Boundaries</h2><p>No voter registration, ballot marking, tabulation, election conduct automation, official certification, live LLM calls, or election-system connector runtime ships in v0.1.0.</p></article><article class="card"><h2>Dependency</h2><p>Pinned to <code>civiccore==0.2.0</code>.</p></article></section></main><footer><p>Apache 2.0 code. CC BY 4.0 docs.</p></footer></body></html>"""
